package com.example.enterpriseapp.service;

import com.example.enterpriseapp.entity.User;
import com.example.enterpriseapp.repository.UserRepository;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

import java.util.List;
import java.util.Optional;

@Service
public class UserService {

    private final UserRepository userRepository;

    @Autowired
    public UserService(UserRepository userRepository) {
        this.userRepository = userRepository;
    }

    @Transactional
    public User createUser(User user) {
        // Basic validation or business logic can be added here
        if (userRepository.findByUsername(user.getUsername()).isPresent()) {
            throw new IllegalArgumentException("Username already exists: " + user.getUsername());
        }
        if (userRepository.findByEmail(user.getEmail()).isPresent()) {
            throw new IllegalArgumentException("Email already exists: " + user.getEmail());
        }
        return userRepository.save(user);
    }

    @Transactional(readOnly = true)
    public Optional<User> getUserById(Long id) {
        return userRepository.findById(id);
    }

    @Transactional(readOnly = true)
    public Optional<User> getUserByUsername(String username) {
        return userRepository.findByUsername(username);
    }

    @Transactional(readOnly = true)
    public List<User> getAllUsers() {
        return userRepository.findAll();
    }

    @Transactional
    public User updateUser(Long id, User userDetails) {
        return userRepository.findById(id).map(user -> {
            user.setUsername(userDetails.getUsername());
            user.setEmail(userDetails.getEmail());
            user.setFirstName(userDetails.getFirstName());
            user.setLastName(userDetails.getLastName());
            return userRepository.save(user);
        }).orElseThrow(() -> new RuntimeException("User not found with id " + id));
    }

    @Transactional
    public void deleteUser(Long id) {
        if (!userRepository.existsById(id)) {
            throw new RuntimeException("User not found with id " + id);
        }
        userRepository.deleteById(id);
    }

    // Example of a transactional method that performs multiple operations
    // For user management, this could be a registration process that involves
    // creating a user and perhaps logging an audit event.
    @Transactional
    public User registerUserAndPerformAdditionalActions(User user) {
        User savedUser = createUser(user); // This call is also transactional, but nested.
                                           // Outer transaction manages the whole flow.
        // Simulate an additional action that needs to be part of the same transaction
        // e.g., create an associated profile entry, log a detailed registration event to another table.
        // If an error occurs here, createUser would also be rolled back.
        System.out.println("User " + savedUser.getUsername() + " registered successfully. Performing additional actions...");
        // Example: auditService.logUserRegistration(savedUser.getId());
        return savedUser;
    }
}

